#include <bits/stdc++.h>
using namespace std;

const int N=1e6;
const double eps=1e-7;

struct Edge{
    int u,v,w;
}edge[N*5];

struct Node{
    int to;
    double val;
};

int n,m,f[N],cnt[N],q[N],hh,tt;
double dis[N];
bool inq[N];
vector<Node> e[N];

bool check(double mid){
    for(int i=1;i<=n+1;i++) e[i].clear(),cnt[i]=0,inq[i]=0;
    for(int i=1;i<=m;i++){
        int u=edge[i].u,v=edge[i].v,w=edge[i].w;
        e[u].push_back({v,mid*w-f[v]});
    }
    for(int i=1;i<=n;i++) e[n+1].push_back({i,0});
    for(int i=1;i<=n+1;i++) dis[i]=1e18;
    dis[n+1]=0;
    hh=1,tt=0;
    q[++tt]=n+1;
    inq[n+1]=1;
    while(hh<=tt){
        int x=q[hh++];
        inq[x]=0;
        for(Node y:e[x])
            if(dis[y.to]>dis[x]+y.val){
                dis[y.to]=dis[x]+y.val;
                cnt[y.to]++;
                if(cnt[y.to]>n+2) return true;
                if(!inq[y.to]){
                    q[++tt]=y.to;
                    inq[y.to]=1;
                }
            }
    }
    return false;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&f[i]);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    double l=0,r=1e6;
    while(l+eps<r){
        double mid=(l+r)/2;
        if(check(mid))
            l=mid;
        else
            r=mid;
    }
    printf("%.2lf",l);
    return 0;
}
